67.         public override bool Equals(object obj) => obj is ArmEnvironment other && Equals(other);
68. 
69.         /// <inheritdoc />
70.         public bool Equals(ArmEnvironment other) => string.Equals(Audience, other.Audience, StringComparison.Ordinal) && Endpoint.Equals(other.Endpoint);
71. 
